import { dataUri } from "./manifest";
const cache = new Map();
function fetchSession(uri) {
    let p = cache.get(uri);
    if (!p) {
        p = fetch(dataUri(uri)).then((r) => {
            if (!r.ok)
                throw new Error(`session fetch failed: ${r.status}`);
            return r.json();
        });
        cache.set(uri, p);
    }
    return p;
}
export function makeReplaySource(uriById) {
    return {
        mode: "replay",
        async loadHeader(sessionId) {
            const s = await fetchSession(uriById(sessionId));
            return {
                id: s.id,
                tenant: s.tenant,
                project: s.project,
                user: s.user,
                title: s.title,
                started_at: s.started_at,
                ended_at: s.ended_at,
                duration_ms: s.duration_ms,
                turn_count: s.turn_count,
                status: s.status,
                model_class: s.model_class,
                scores: s.scores,
                scenario: s.scenario,
            };
        },
        async snapshot(sessionId) {
            const s = await fetchSession(uriById(sessionId));
            return { turns: s.turns, observations: s.observations, closed: s.status === "closed" };
        },
        // No subscribe — replay has no incremental stream beyond the snapshot.
        close() {
            // cache is intentionally session-lifetime; nothing to clean up.
        },
    };
}
