const BASE = (import.meta.env.BASE_URL ?? "/").replace(/\/$/, "");
export async function loadManifest() {
    const res = await fetch(`${BASE}/data/manifest.json`);
    if (!res.ok)
        throw new Error(`manifest fetch failed: ${res.status}`);
    const data = (await res.json());
    if (data.schema_version !== "1") {
        throw new Error(`manifest schema_version ${data.schema_version} unsupported`);
    }
    return data;
}
export function dataUri(path) {
    // The on-disk session_uri is "data/sessions/{id}.json"; the frontend serves it from BASE/data/...
    return `${BASE}/${path.replace(/^\/+/, "")}`;
}
