import { useEffect, useRef, useState } from "react";
export function useSessionPlayer(sessionId, source) {
    const [state, setState] = useState({
        status: "loading",
        header: null,
        turns: [],
        observations: [],
        error: null,
    });
    const subRef = useRef(null);
    useEffect(() => {
        let cancelled = false;
        subRef.current?.unsubscribe();
        subRef.current = null;
        setState({ status: "loading", header: null, turns: [], observations: [], error: null });
        (async () => {
            try {
                const header = await source.loadHeader(sessionId);
                if (cancelled)
                    return;
                const snap = await source.snapshot(sessionId);
                if (cancelled)
                    return;
                setState({
                    status: snap.closed ? "finished" : "ready",
                    header,
                    turns: snap.turns,
                    observations: snap.observations,
                    error: null,
                });
                if (source.mode === "live" && source.subscribe) {
                    const sub = source.subscribe(sessionId);
                    sub.onTurn((t) => setState((s) => ({ ...s, turns: [...s.turns, t] })));
                    sub.onObservation((o) => setState((s) => ({ ...s, observations: [...s.observations, o] })));
                    sub.onClose(() => setState((s) => ({ ...s, status: "finished" })));
                    subRef.current = sub;
                }
            }
            catch (err) {
                if (cancelled)
                    return;
                setState((s) => ({ ...s, status: "failed", error: err.message }));
            }
        })();
        return () => {
            cancelled = true;
            subRef.current?.unsubscribe();
            subRef.current = null;
            source.close();
        };
    }, [sessionId, source]);
    return state;
}
