// Deep-link helpers for the Conditions page.
//
// Anchor format:
//   #cond-{CODE}        → Conditions tab, expand condition CODE
//   #cat-{slug}         → Categories tab, expand the matching category
//
// The Conditions page uses the hash to drive both tab selection and
// expansion-on-load, so any of these URLs are sufficient on their own.
export function slugifyCategory(name) {
    return name.toLowerCase().replace(/\s+/g, "-").replace(/[^a-z0-9-]/g, "");
}
export function conditionAnchor(code) {
    return `cond-${code}`;
}
export function categoryAnchor(name) {
    return `cat-${slugifyCategory(name)}`;
}
export function conditionHref(tenant, code) {
    return `/${tenant}/conditions#${conditionAnchor(code)}`;
}
export function categoryHref(tenant, name) {
    return `/${tenant}/conditions#${categoryAnchor(name)}`;
}
/**
 * Build a Sessions URL with filter query params preset. Pass only the
 * filters you want preselected; empty/undefined values are dropped.
 */
export function sessionsHref(tenant, query) {
    if (!query)
        return `/${tenant}/sessions`;
    const params = new URLSearchParams();
    for (const [k, v] of Object.entries(query)) {
        if (v)
            params.set(k, v);
    }
    const q = params.toString();
    return q ? `/${tenant}/sessions?${q}` : `/${tenant}/sessions`;
}
export function parseAnchor(hash) {
    const h = hash.replace(/^#/, "");
    if (h.startsWith("cond-"))
        return { tab: "conditions", target: h.slice(5) };
    if (h.startsWith("cat-"))
        return { tab: "categories", target: h.slice(4) };
    return null;
}
