const BASE = (import.meta.env.BASE_URL ?? "/").replace(/\/$/, "");
let cache = null;
export function loadTaxonomy() {
    if (!cache) {
        cache = fetch(`${BASE}/data/taxonomy.json`).then((r) => {
            if (!r.ok)
                throw new Error(`taxonomy fetch failed: ${r.status}`);
            return r.json();
        });
    }
    return cache;
}
