import { create } from "zustand";
import { loadManifest } from "../sources/manifest";
export const useManifestStore = create((set, get) => ({
    manifest: null,
    error: null,
    loading: false,
    async ensureLoaded() {
        if (get().manifest || get().loading)
            return;
        set({ loading: true, error: null });
        try {
            const manifest = await loadManifest();
            set({ manifest, loading: false });
        }
        catch (err) {
            set({ error: err.message, loading: false });
        }
    },
}));
